tableData:
{{
  getInvoices.data.filter(item => {
    // 1. Must be an Invoice
    if (item.document_type !== 'Invoice') return false;

    // 2. Filter by Invoice Status
    // (If nothing is selected, we show all, otherwise we filter)
    const invSelection = CheckboxGroupInv.selectedOptionValues;
    const matchInv = invSelection.length === 0 || invSelection.includes(item.invoice_status);

    // 3. Filter by Delivery Status
    const delSelection = CheckboxGroupDel.selectedOptionValues;
    const matchDel = delSelection.length === 0 || delSelection.includes(item.delivery_status);

    return matchInv && matchDel;
  })
}}
